mapper.update:
UPDATE STOCIVAP SET
    AP_REQ_SUBJECT = #{AP_REQ_SUBJECT}
    , BILL_DATE = #{BILL_DATE}
    , BILL_ATT_FILE_NUM = #{BILL_ATT_FILE_NUM}
    , VENDOR_ATT_FILE_NUM = #{ATT_FILE_NUM}
    , VENDOR_RMK = #{RMK_TEXT_NUM}
    , SIGN_STATUS = #{SIGN_STATUS}
    , GUAR_TYPE = #{GUAR_TYPE}
    , GUAR_PERCENT = #{GUAR_PERCENT}
    , GUAR_QT = #{GUAR_QT}
    , GUAR_AMT = #{GUAR_AMT}
    , GUAR_ATT_FILE_NUM = #{GUAR_ATT_FILE_NUM}
    , INSU_STATUS = CASE WHEN #{TYPE} = 'GUAR' THEN #{INSU_STATUS} ELSE INSU_STATUS END
    , GUAR_RMK = #{GUAR_RMK}
    , VENDOR_USER_NM = #{VENDOR_USER_NM}
    , VENDOR_TEL_NUM = #{VENDOR_TEL_NUM}
    , VENDOR_CELL_NUM = #{VENDOR_CELL_NUM}
    , PAY_BANK = #{PAY_BANK}
    , PAY_ACCOUNT_NUM = #{PAY_ACCOUNT_NUM}
    , PAY_ACC_NM = #{PAY_ACC_NM}
    , PAY_ATT_FILE_NUM = #{PAY_ATT_FILE_NUM}
    , GUAR_TYPE2 = #{GUAR_TYPE2}
    , GUARANTEER = #{GUARANTEER}
    , BOND_BEGN_DATE = #{BOND_BEGN_DATE}
    , BOND_FNSH_DATE = #{BOND_FNSH_DATE}
    , AP_REQ_DATE = CASE WHEN #{TYPE} = 'SEND' THEN SYSDATE ELSE AP_REQ_DATE END
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD  = #{ses.gateCd}
  AND AP_NUM   = #{AP_NUM}
  AND INV_NUM  = #{INV_NUM}
  AND PO_NUM   = #{PO_NUM}
  AND BUYER_CD = #{BUYER_CD}
  AND DEPT_CD  = #{DEPT_CD}
  AND PAY_CNT  = #{PAY_CNT}
  AND PY_BUYER_CD = #{PY_BUYER_CD}
  AND PY_DEPT_CD  = #{PY_DEPT_CD}

UPDATE STOCIVAP SET
    SIGN_VALUE = #{SIGN_VALUE}
    , SIGN_RANDOM = #{SIGN_RANDOM}
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD  = #{ses.gateCd}
  AND AP_NUM   = #{AP_NUM}
  AND INV_NUM  = #{INV_NUM}
  AND PO_NUM   = #{PO_NUM}
  AND BUYER_CD = #{BUYER_CD}
  AND DEPT_CD  = #{DEPT_CD}
  AND PAY_CNT  = #{PAY_CNT}
  AND PY_BUYER_CD = #{PY_BUYER_CD}
  AND PY_DEPT_CD  = #{PY_DEPT_CD}

UPDATE STOCPODT SET
      PROGRESS_CD = CASE WHEN #{TYPE} = 'SEND' THEN #{PROGRESS_CD} ELSE PROGRESS_CD END
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD  = #{ses.gateCd}
  AND BUYER_CD = #{BUYER_CD}
  AND PO_NUM   = #{PO_NUM}
  AND PO_SQ    = #{PO_SQ}

UPDATE STOCPRDT SET
      MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , PROGRESS_CD = CASE WHEN #{TYPE} = 'SEND' THEN #{PROGRESS_CD} ELSE PROGRESS_CD END
WHERE GATE_CD  = #{ses.gateCd}
  AND (BUYER_CD, PR_NUM, PR_SQ) IN (
  			SELECT PB_BUYER_CD, PR_NUM, PR_SQ
  			  FROM STOCPODT
  			 WHERE GATE_CD  = #{ses.gateCd}
  			   AND BUYER_CD = #{BUYER_CD}
  			   AND PO_NUM   = #{PO_NUM}
  			   AND PO_SQ    = #{PO_SQ}
  	  )
  AND DEL_FLAG = '0'

UPDATE STOCIVAP SET
    DEL_FLAG = '1'
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD   = #{ses.gateCd}
  AND AP_NUM   = #{AP_NUM}
  AND INV_NUM  = #{INV_NUM}
  AND PO_NUM   = #{PO_NUM}
  AND BUYER_CD = #{BUYER_CD}
  AND DEPT_CD  = #{DEPT_CD}
  AND PAY_CNT  = #{PAY_CNT}
  AND PY_BUYER_CD = #{PY_BUYER_CD}
  AND PY_DEPT_CD  = #{PY_DEPT_CD}
